  }
  const list = Array.isArray(raw) ? raw : (raw.results || []);
  // Нормализуем разные shape'ы Plane API:
  //   v1: [{member: {id, display_name, first_name, last_name, email}, role}]
  //   v2: [{id, display_name, ...}]
  //   v3: [{member: '<uuid>', member_first_name: '...', member_email: '...'}]  (плоский)
  const members = list.map(m => {
    const u = (typeof m.member === 'object' && m.member !== null) ? m.member : m;
